def solve(arg1: dict) -> dict:
    track = arg1.get('track')
    gamma_intensity = arg1.get('gamma_intensity', 0)
    theta_intensity = arg1.get('theta_intensity', 0)

    if not track:
        return {'inclusion_percentage': 0, 'listenability': 'pass'}

    total_intensity = gamma_intensity + theta_intensity

    if total_intensity == 0:
        return {'inclusion_percentage': 0, 'listenability': 'pass'}

    if total_intensity > 100:
        inclusion_percentage = 100
        listenability = 'fail'
    else:
        inclusion_percentage = total_intensity
        listenability = 'pass' if total_intensity <= 50 else 'fail'

    return {'inclusion_percentage': inclusion_percentage, 'listenability': listenability}
